function solve(n, edges, k) {
    let max_time = 0;
    for (let e of edges) {
        if (e[2] > max_time) {
            max_time = e[2];
        }
    }

    function is_valid(t) {
        let parent = Array(n).fill(0).map((_, i) => i);
        let count = n;

        function find(u) {
            if (parent[u] !== u) {
                parent[u] = find(parent[u]);
            }
            return parent[u];
        }

        function union(u, v) {
            let root_u = find(u);
            let root_v = find(v);
            if (root_u !== root_v) {
                parent[root_v] = root_u;
                count--;
                return true;
            }
            return false;
        }

        for (let e of edges) {
            if (e[2] > t) {
                union(e[0], e[1]);
            }
        }

        return count >= k;
    }

    let left = 0;
    let right = max_time;
    let answer = max_time;

    while (left <= right) {
        let mid = Math.floor((left + right) / 2);
        if (is_valid(mid)) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

